 1	import React, { FC, PropsWithChildren, SyntheticEvent } from 'react';
 2	
 3	import { Button, ButtonVariant, Flex } from '@patternfly/react-core';
 4	import { PencilAltIcon } from '@patternfly/react-icons';
 5	
 6	type EditButtonProps = PropsWithChildren<{
 7	  isEditable: boolean;
 8	  onEditClick?: () => void;
 9	  testId: string;
10	}>;
11	
12	const EditButton: FC<EditButtonProps> = ({ children, onEditClick, isEditable, testId }) => (
13	  <Button
14	    onClick={(e: SyntheticEvent<HTMLButtonElement>) => {
15	      e.stopPropagation();
16	      onEditClick?.();
17	    }}
18	    data-test-id={testId}
19	    isDisabled={!isEditable}
20	    isInline
21	    variant={ButtonVariant.link}
22	  >
23	    <Flex>
24	      {children}
25	      <PencilAltIcon className="co-icon-space-l" />
26	    </Flex>
27	  </Button>
28	);
29	
30	export default EditButton;

